// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.trace;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

import java.util.List;
import java.util.concurrent.atomic.AtomicReference;

import org.junit.jupiter.api.Test;

class QueryTraceContextTest {

	@Test
	void activateShouldExposeAndRestoreNestedRecorders() throws Exception {
		QueryTraceRecorder outerRecorder = new QueryTraceRecorder(List.of());
		QueryTraceRecorder innerRecorder = new QueryTraceRecorder(List.of());

		assertThat(QueryTraceContext.getRecorder()).isNull();

		try (QueryTraceContext.Activation outer = QueryTraceContext.activate(outerRecorder)) {
			assertThat(QueryTraceContext.getRecorder()).isSameAs(outerRecorder);

			try (QueryTraceContext.Activation inner = QueryTraceContext.activate(innerRecorder)) {
				assertThat(QueryTraceContext.getRecorder()).isSameAs(innerRecorder);
			}

			assertThat(QueryTraceContext.getRecorder()).isSameAs(outerRecorder);
		}

		assertThat(QueryTraceContext.getRecorder()).isNull();
	}

	@Test
	void outOfOrderCloseShouldNotClobberCurrentRecorder() throws Exception {
		QueryTraceRecorder outerRecorder = new QueryTraceRecorder(List.of());
		QueryTraceRecorder innerRecorder = new QueryTraceRecorder(List.of());
		QueryTraceContext.Activation outer = QueryTraceContext.activate(outerRecorder);
		QueryTraceContext.Activation inner = QueryTraceContext.activate(innerRecorder);

		try {
			assertThat(QueryTraceContext.getRecorder()).isSameAs(innerRecorder);

			outer.close();
			assertThat(QueryTraceContext.getRecorder()).isSameAs(innerRecorder);

			inner.close();
			assertThat(QueryTraceContext.getRecorder()).isSameAs(outerRecorder);

			outer.close();
			assertThat(QueryTraceContext.getRecorder()).isNull();
		} finally {
			inner.close();
			outer.close();
		}
	}

	@Test
	void activateShouldRemainThreadLocal() throws Exception {
		QueryTraceRecorder recorder = new QueryTraceRecorder(List.of());
		AtomicReference<QueryTraceRecorder> workerRecorder = new AtomicReference<>(recorder);

		try (QueryTraceContext.Activation ignored = QueryTraceContext.activate(recorder)) {
			Thread thread = new Thread(() -> workerRecorder.set(QueryTraceContext.getRecorder()));
			thread.start();
			thread.join();

			assertThat(workerRecorder).hasValue(null);
			assertThat(QueryTraceContext.getRecorder()).isSameAs(recorder);
		}

		assertThat(QueryTraceContext.getRecorder()).isNull();
	}

	@Test
	void activateShouldRejectNullRecorder() {
		assertThatThrownBy(() -> QueryTraceContext.activate(null))
				.isInstanceOf(NullPointerException.class)
				.hasMessage("Recorder was null");
	}
}
